import React, { useEffect, useState } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const user = JSON.parse(localStorage.getItem('user')); // Lấy thông tin user để kiểm tra quyền admin

    // 1. Lấy danh sách bài hát từ server
    const fetchSongs = async () => {
        try {
            const res = await axios.get('http://localhost:5000/api/songs');
            setSongs(res.data);
        } catch (err) {
            console.error("Lỗi khi tải danh sách nhạc", err);
        }
    };

    useEffect(() => {
        fetchSongs();
    }, []);

    // 2. Hàm xử lý xóa bài hát
    const handleDelete = async (id) => {
        if (window.confirm("Bạn có chắc chắn muốn xóa bài hát này và file gốc không?")) {
            try {
                await axios.delete(`http://localhost:5000/api/songs/${id}`);
                alert("Đã xóa sạch dữ liệu và file!");
                fetchSongs(); // Tải lại danh sách sau khi xóa
            } catch (err) {
                alert("Lỗi khi xóa: " + (err.response?.data?.message || err.message));
            }
        }
    };

    return (
        <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
            <h2 style={{ borderBottom: '2px solid #1db954', paddingBottom: '10px' }}>Khám phá âm nhạc</h2>
            
            <div style={{ display: 'grid', gridTemplateColumns: 'reap(auto-fill, minmax(200px, 1fr))', gap: '20px', marginTop: '20px' }}>
                {songs.map((song) => (
                    <div key={song._id} style={cardStyle}>
                        <img 
                            src={`http://localhost:5000${song.imageUrl}`} 
                            alt={song.title} 
                            style={{ width: '100%', height: '180px', objectFit: 'cover', borderRadius: '10px' }} 
                        />
                        <h4 style={{ margin: '10px 0 5px 0' }}>{song.title}</h4>
                        <p style={{ color: '#666', fontSize: '14px' }}>{song.artist}</p>
                        
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '10px' }}>
                            <button style={playBtnStyle}>▶ Nghe</button>
                            
                            {/* Chỉ hiện nút xóa nếu là admin (hoặc hiện mặc định nếu bạn chưa phân quyền) */}
                            <button 
                                onClick={() => handleDelete(song._id)} 
                                style={deleteBtnStyle}
                            >
                                🗑️ Xóa
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

// --- CSS Inline cho gọn ---
const cardStyle = {
    background: '#fff',
    padding: '15px',
    borderRadius: '15px',
    boxShadow: '0 4px 10px rgba(0,0,0,0.1)',
    transition: 'transform 0.2s'
};

const playBtnStyle = {
    background: '#1db954',
    color: 'white',
    border: 'none',
    padding: '5px 15px',
    borderRadius: '20px',
    cursor: 'pointer',
    fontWeight: 'bold'
};

const deleteBtnStyle = {
    background: '#ff4d4d',
    color: 'white',
    border: 'none',
    padding: '5px 10px',
    borderRadius: '5px',
    cursor: 'pointer',
    fontSize: '12px'
};

export default Home;
